                    [void]$script:pnpDevicesAsyncResult.AsyncWaitHandle.WaitOne(15000)
                }
                $script:cachedPnpDevicesAll = @($script:pnpDevicesRunspace.EndInvoke($script:pnpDevicesAsyncResult))
            } catch {
