$_usbButtonPairW = ($_usbXSave + $_usbWSave) - $_usbXSet
$_usbSecretCenteredLeft = $_usbXSet + [int][Math]::Round(($_usbButtonPairW - $_usbSecretPreferred.Width) / 2)
