        $btnSaveNicIMOD.Height = $_nicButtonH
        $btnSaveNicIMOD.Left = $_xSave
        $btnSaveNicIMOD.Top = $_nicButtonTop
        $btnSaveNicIMOD.Tag = $device
        $btnSaveNicIMOD.BackColor = $script:colBlack
